import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.client.RestTemplate;

import java.util.Arrays;
import java.util.List;
import java.util.regex.Pattern;

@RestController
public class WebhookController {

    private final RestTemplate restTemplate = new RestTemplate();
    private final List<String> allowedDomains;

    public WebhookController(@Value("${allowed-domains}") String[] allowedDomains) {
        this.allowedDomains = Arrays.asList(allowedDomains);
    }

    @PostMapping("/webhook")
    public ResponseEntity<String> handleWebhook(@RequestBody String requestBody, HttpHeaders headers) {
        String url = headers.get("X-URL").get(0);

        if (!isAllowedDomain(url)) {
            return new ResponseEntity<>("Invalid domain", HttpStatus.FORBIDDEN);
        }

        try {
            ResponseEntity<String> response = restTemplate.exchange(url, HttpMethod.GET, null, String.class);
            return response;
        } catch (Exception e) {
            return new ResponseEntity<>(e.getMessage(), HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }

    private boolean isAllowedDomain(String url) {
        Pattern pattern = Pattern.compile("^(https?://)([a-zA-Z0-9]+([.-][a-zA-Z0-9]+)*\\.)+[a-zA-Z]{2,}$");
        return allowedDomains.stream()
                .anyMatch(domain -> pattern.matcher(url).matches());
    }
}